-- BLOCO 1 (parte 2/6) — Revisão linguística pílulas PII (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Continuo fazendo o que sempre fiz. Mas algo dentro não está mais nisso.", "tension_label": "Eu ↔ Papel"}, "m2": {"scene": "Renata foi a organizadora do escritório por oito anos. Sabia o que cada um precisava antes de pedirem. Conseguia ver os buracos e preencher. 'Você é insubstituível', dizia o chefe.\n\nMês passado, o parceiro pediu pra ela parar de organizar a vida deles. Renata parou. Por uma semana, o apartamento foi à deriva. Na terceira semana, ela parou de notar a bagunça e só sentia cansaço.\n\nNum domingo à noite, sozinha na mesa, reorganizando um drive compartilhado. Tudo em ordem, tudo dependendo dela. Ela se perguntou: se eu parar de fazer isso, ainda existo?", "question": "O que Renata protegia ao se fazer essencial?"}, "m4": {"question": "Depois dessas respostas — onde você sentiu o você real, e onde sentiu o papel se encenando?", "instruction": "Nomeie um momento concreto das suas respostas onde os dois se separaram. Uma ou duas frases bastam."}, "m3_1": {"context": "Testa se a pessoa localiza a tensão de PII fora (o papel mudou) ou dentro (algo em mim mudou). Núcleo do diagnóstico de PII.", "question": "Quando você está fazendo algo em que sempre foi bom, mas não parece mais 'você', o que parece mais verdade — que o papel mudou, ou que você mudou?", "pole_left": "O papel mudou", "pole_right": "Eu mudei"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Aceito. Alinhamento com a expectativa dos outros já basta.", "followup": "Testar se a hesitação é intuição ou medo. A chance de descobrir o que você de fato quer.", "followup_type": "cost"}, {"key": "B", "text": "Recuso. Confio na hesitação.", "followup": "A oportunidade em si. Certeza sobre se está recusando porque algo está errado ou porque está tentando virar outra pessoa.", "followup_type": "cost"}, {"key": "C", "text": "Pergunto o que o papel de fato exige vs. o que as pessoas projetam nele.", "followup": "O que você estava tentando separar — o trabalho real da identidade?", "followup_type": "question"}, {"key": "D", "text": "Aceito provisoriamente — me comprometo por seis meses e reavalio.", "followup": "O que fez um prazo parecer segurança em vez de evitação?", "followup_type": "question"}], "scenario": "Te ofereceram um papel que os outros acham que cabe perfeitamente em você. Mas algo em você hesita. A oferta é real. O prazo é amanhã."}, "m3_3": {"q1": "Lembre de um momento em que você fez algo importante que parecia ser de fato você, não só seu papel.", "q2": "O que tornou possível agir como você mesmo naquele momento?", "scoring_note": "Buscar: qual era a distância entre o papel e o eu real? Que permissão interna ou externa fez essa distância segura? (Resolução de PII frequentemente exige achar onde o papel termina e a pessoa começa.) L1.3 transversal: testar se autenticidade fora-do-papel muda o padrão de qualidade.", "q_transversal": "Naquele momento de ser você mesmo — o que você fez foi melhor, pior, ou só diferente do que quando você está no papel?"}}$rdwth_final$::jsonb
WHERE id = '9284bbd5-bb30-4d1d-a5c1-e452e4f29ed7';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Sou bom nisso. Só não sei mais quem é bom nisso.", "tension_label": "Eu ↔ Papel"}, "m2": {"scene": "Marcos era o pai que aparecia — pros filhos, pra rede toda da família. Lembrava aniversários, organizava a reunião, sabia quem precisava de ajuda. Era bom nisso. Era genuinamente ele.\n\nMas aí os filhos cresceram. As reuniões diminuíram. O papel mudou. Ele era menos o organizador e mais... estava ali. Mas pra quê?\n\nEncontrando um amigo antigo, conversaram. O amigo perguntou: 'O que você anda fazendo? Não pra ninguém. O que é seu?' Marcos não soube responder. E sentado ali, percebeu que tinha passado tanto tempo sendo necessário que não tinha certeza se tinha algo que era só dele.", "question": "Do que Marcos tinha medo se parasse de ser o que segurava tudo?"}, "m4": {"question": "Quando você sentiu pela primeira vez que estava desaparecendo nesse papel, e quando notou pela primeira vez que isso estava acontecendo?", "instruction": "Conte os dois momentos, brevemente. Não precisa lembrar das datas."}, "m3_1": {"context": "Testa se externaliza (é a condição) ou internaliza (é o descompasso de identidade).", "question": "Quando algo em que você devia ser bom começa a parecer oco, você costuma se perguntar se está esgotado, ou se algum dia foi de fato a pessoa que aquele papel descrevia?", "pole_left": "Estou esgotado", "pole_right": "Eu nunca fui essa pessoa"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Me retiro completamente. Eles vão se virar sem o meu papel.", "followup": "Seu lugar na vida deles. Saber se você importa sem o papel.", "followup_type": "cost"}, {"key": "B", "text": "Explico por que faço isso — que é como eu cuido, que importa pra mim.", "followup": "Aceitar que eles podem não querer seu cuidado nessa forma.", "followup_type": "cost"}, {"key": "C", "text": "Pergunto a eles do que de fato precisam de mim, sem o meu papel de sempre.", "followup": "O que te assustou em ouvir a resposta?", "followup_type": "question"}, {"key": "D", "text": "Mantenho o papel mas faço diferente — menos controlador, mais de apoio.", "followup": "Qual a diferença entre mudar o papel e mudar quem você é?", "followup_type": "question"}], "scenario": "Seu parceiro/família/amigo próximo pediu pra você ser menos [seu papel]. Menos o organizador. Menos o provedor. Menos o forte. Estão dizendo que precisam de você diferente.\n\nVocê consegue. Consegue aparecer diferente. Mas significa admitir que o papel que você construiu não é só algo que você faz — é como você importa pra eles."}, "m3_3": {"q1": "Lembre de uma vez em que decepcionou alguém ou falhou no seu papel habitual, e isso não destruiu quem você é.", "q2": "O que aprendeu sobre si mesmo nessa falha?", "scoring_note": "Testa se conseguem separar identidade de performance. Se respondem 'eu não sou só meu papel' vs. 'me aceitaram mesmo assim' — revela se o deslocamento é interno ou externo. L1.3 transversal: testar se a falha recalibra os critérios de suficiência.", "q_transversal": "Quando você falhou no papel — o que você considerava 'bom o suficiente' mudou? Ou ficou igual?"}}$rdwth_final$::jsonb
WHERE id = 'ce969518-95e8-4093-aa30-5b3528c9459e';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "O papel cabe perfeito. Então por que sinto que estou desaparecendo?", "tension_label": "Eu ↔ Papel"}, "m2": {"scene": "Bruna era a realizadora — ditando o ritmo, com o plano, indo pra próxima coisa. Tinha levado ela longe. Era bem-sucedida. Respeitada.\n\nDaí ela bateu no alvo. Sem próxima coisa. Tentou criar urgência, pegar mais coisas, mas parecia forçado. Quando desacelerou, não sabia como só ser. Não tinha versão de si mesma que não estivesse indo em direção a algo.\n\nUma terapeuta perguntou: 'O que aconteceria se você parasse de realizar?' Bruna respondeu: 'Eu não teria identidade.' A terapeuta perguntou: 'Isso é verdade? Ou é o que você arranjou pra ser verdade?' Bruna saiu confusa, sem conseguir dizer se tinha medo de não realizar ou se simplesmente nunca tinha construído mais nada.", "question": "O que Bruna teria que aceitar sobre si mesma pra parar de realizar?"}, "m4": {"question": "Se seu papel terminasse amanhã, do que você sentiria mais falta — do trabalho em si, ou de ser a pessoa que faz?", "instruction": "Escolha um. Conte o porquê em uma ou duas frases — sem filtro."}, "m3_1": {"context": "Revela se o custo do papel está no trabalho em si ou na identidade que ele carrega.", "question": "Neste momento, você está mais apegado a fazer a coisa bem feita, ou a ser conhecido como alguém que faz a coisa bem feita?", "pole_left": "Fazer bem feito importa mais", "pole_right": "Ser reconhecido importa mais"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Aposto mais na competência. Fico ainda mais confiável.", "followup": "A proximidade que essa pessoa está oferecendo. Sua própria permissão pra penar.", "followup_type": "cost"}, {"key": "B", "text": "Admito que tenho medo de ser vulnerável com pessoas.", "followup": "Controle. A segurança de ficar atrás do papel.", "followup_type": "cost"}, {"key": "C", "text": "Mostro pra elas uma coisinha pequena com a qual estou penando.", "followup": "O que tornou possível arriscar isso?", "followup_type": "question"}, {"key": "D", "text": "Me deixo ser pouco confiável — uma vez. De propósito. E vejo o que sobrevive.", "followup": "O que você aprendeu sobre quem é quando o papel falhou?", "followup_type": "question"}], "scenario": "Você foi o competente. O responsável. Aquele em quem todos confiam. Agora alguém percebeu e está nomeando: 'Você está sempre ligado. Nunca é vulnerável. Nunca deixa ninguém te ajudar.'\n\nEla está certa. E parte de você está aliviada de ter ouvido. Outra parte está em pânico. Porque se você não é o competente, perde a única identidade que construiu."}, "m3_3": {"q1": "Quando você escolheu fazer algo menos bem feito, ou nem fazer, porque importava mais que realizar?", "q2": "Como você soube que essa escolha era a certa?", "scoring_note": "Endereça diretamente se conseguem sair do papel. A resposta revela se têm valores separados das exigências do papel. L1.3 transversal: testar como determinam suficiência ao sair de alta performance.", "q_transversal": "Quando você escolheu fazer menos — como você soube o que ainda era suficiente?"}}$rdwth_final$::jsonb
WHERE id = '9d688602-189b-49b9-99f8-f3f7b2237b9f';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Continuo sendo a pessoa que todos precisam que eu seja. Mas não tenho certeza se essa pessoa ainda sou eu.", "tension_label": "Eu ↔ Papel"}, "m2": {"scene": "Henrique era o paramédico — aquele que você chama quando tudo está desabando. Em casa, mesma coisa: arrumava qualquer coisa, resolvia tudo, e ninguém precisava se preocupar com ele. Era esse cara que ele era.\n\nDaí teve um colapso. Pela primeira vez, teve que admitir que existia algo nele que ele não conseguia consertar. A equipe cobriu os turnos. A família apareceu — mais cuidadosa, mais perto. A parceira, em vez de se afastar do Henrique que agora precisava de cuidado, chegou mais junto.\n\nMas Henrique estava aterrorizado. Se as pessoas gostavam dele quando não era o consertador, quem ele tinha sido todos esses anos? E se ele melhorasse, ia voltar a ser aquele que todos precisavam? E se voltasse, perderia isso?", "question": "Do que Henrique tinha medo de desaparecer se admitisse que o papel não era o ele real?"}, "m4": {"question": "Qual seria a parte mais difícil de admitir que algo dentro de você não está mais com seu papel?", "instruction": "Nomeie o que você perderia, ou o que se tornaria real, se dissesse em voz alta. Algumas frases."}, "m3_1": {"context": "Endereça diretamente o que o papel está protegendo — relevância externa ou coerência interna.", "question": "Se você abandonasse esse papel completamente, do que teria mais medo — que ninguém precisasse mais de você, ou de finalmente ter que descobrir quem você é sem ele?", "pole_left": "Ninguém precisaria de mim", "pole_right": "Eu teria que descobrir quem sou"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Fico no papel mais tempo. Acho um jeito de estender.", "followup": "A chance de descobrir o que vem depois. Tempo.", "followup_type": "cost"}, {"key": "B", "text": "Saio completamente e me comprometo a reconstruir do zero.", "followup": "A segurança de saber ser bom em algo. Certeza.", "followup_type": "cost"}, {"key": "C", "text": "Demoro nisso antes de decidir: quem eu era antes do papel? Do que cuidava que deixei de lado?", "followup": "O que você lembrou sobre si mesmo?", "followup_type": "question"}, {"key": "D", "text": "Faço transição lenta — desligo o papel antigo enquanto exploro o que vem.", "followup": "O que você está construindo nesse espaço entre papéis?", "followup_type": "question"}], "scenario": "Seu papel está chegando ao fim. Aposentadoria. Mudança de carreira. Os filhos não precisam mais de você como precisavam. Sua expertise está ficando obsoleta. Ou você está escolhendo sair.\n\nO alívio é imediato. Você também está aterrorizado. Porque não sabe quem é sem isso. E agora tem que descobrir."}, "m3_3": {"q1": "Pense em alguém que te vê fora do seu papel. O que essa pessoa vê que outros não veem?", "q2": "Essa pessoa está certa? Esse é o você real?", "scoring_note": "Revela se confiam numa versão alternativa de si mesmos. Resolução de PII frequentemente depende de achar pelo menos uma pessoa que valida o eu fora-do-papel. L1.3 transversal: testar se contextos fora-do-papel têm critérios diferentes de suficiência.", "q_transversal": "A pessoa que te vê fora do papel cobra de você um padrão diferente do que você cobra de si mesmo?"}}$rdwth_final$::jsonb
WHERE id = '3123cfe4-d164-4df6-8e40-f7ddde6e95d5';